// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
if(typeof window == 'undefined'){
	runTemplate();
	gs.addInfoMessage('Tasker is running the process to create the Tasks in your Template');
}

function runTemplate()
{

	// RAJ STRY0063867 - this story is an integration story, call the Script instead of calling the event.
	//var param1 = current.u_temp_instance_notation +" npaa$ " + current.u_temp_objective;
	//gs.eventQueue('x_153465_discovert.Start_Template', current, param1,  gs.getUserID());
	// STRY0063859 - change to use the new helper functions so all calls are consistent.
	var tTH = new TaskTemplateHelpers();
	var templateInputs = {};
	templateInputs = tTH.loadInputDefaultFromTemplate(current);
	var strInstanceNotation = current.getValue('u_temp_instance_notation');
	// if the user didn't set a temp notation, then pull description from the Template
	if(strInstanceNotation == ''){
		strInstanceNotation =current.getValue('description');	
	}
	templateInputs.templateNotation = strInstanceNotation;
	var strObjective = current.getValue('u_temp_objective');
	// if the user didn't set a temp objective, then pull objective from the Template
	if(strObjective == ''){
		strObjective =current.getValue('u_objective');	
	}
	templateInputs.objective = strObjective;
	tTH.startTemplateWithID(current.getValue('sys_id'), true, templateInputs);

}
